# String utility functions for text processing

def reverse_string(s: str) -> str:
    """Reverse a string character by character"""
    result: str = ""
    i: int = len(s) - 1
    while i >= 0:
        result += s[i]
        i -= 1
    return result

def count_vowels(s: str) -> int:
    """Count vowels in a string"""
    vowels: str = "aeiouAEIOU"
    count: int = 0
    i: int = 0
    while i < len(s):
        char: str = s[i]
        if char in vowels:
            count += 1
        i += 1
    return count

class TextAnalyzer:
    text: str
    word_count: int

    def __init__(self, text: str):
        self.text = text
        self.word_count = self._calculate_word_count()

    @private
    def _calculate_word_count(self) -> int:
        """Count words by splitting on spaces"""
        if len(self.text) == 0:
            return 0

        count: int = 1
        i: int = 0
        while i < len(self.text):
            if self.text[i] == ' ':
                count += 1
            i += 1
        return count

    def get_summary(self) -> str:
        """Get text analysis summary"""
        vowel_count: int = count_vowels(self.text)
        return f"Words: {self.word_count}, Vowels: {vowel_count}, Length: {len(self.text)}"
